Greedy randomized adaptive search inserting each ship into the best feasible assign based on marginal cost increase, with fallback to a new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible   bool
	}
	const alpha = 0.3
	newAssignsCount := 0
	for jj := range oris {
		bestCandidates := make([]candidate, 0, MAXASSIGNS*2)
		totalFeasible := 0
		minDelta := math.MaxFloat64
		maxDelta := -math.MaxFloat64
		ori, des := oris[jj], dess[jj]
		shipID := total_ship + jj
		for ii := 0; ii < dispatch.AssignsLen+newAssignsCount; ii++ {
			idx := ii % MAXASSIGNS
			oldCost := dispatch.Assigns[idx].Cost
			if oldCost < 0 {
				continue
			}
			saved := dispatch.Assigns[idx].StationCurrent
			ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					delta := dispatch.Assigns[idx].Cost - oldCost
					bestCandidates = append(bestCandidates, candidate{idx, delta, true})
					totalFeasible++
					if delta < minDelta {
						minDelta = delta
					}
					if delta > maxDelta {
						maxDelta = delta
					}
				}
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].StationCurrent = saved
				dispatch.Assigns[idx].GenRoute()
			}
		}
