func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    shipIdBase := total_ship
    for orderIdx := range oris {
        shipId := shipIdBase + orderIdx
        bestAssignIdx := -1
        bestCostDelta := 1e100
        originalCosts := make([]float64, dispatch.AssignsLen)
        originalRoutesValid := make([]bool, dispatch.AssignsLen)
        // Save current state of each assign
        for i := 0; i < dispatch.AssignsLen; i++ {
            originalCosts[i] = dispatch.Assigns[i].Cost
            originalRoutesValid[i] = dispatch.Assigns[i].Cost >= 0
        }
        // Try inserting into existing assigns
        for i := 0; i < dispatch.AssignsLen; i++ {
            if !originalRoutesValid[i] {
                continue
            }
            savedCost := dispatch.Assigns[i].Cost
            if dispatch.Assigns[i].AddShip(shipId, oris[orderIdx], dess[orderIdx]) {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costDelta := dispatch.Assigns[i].Cost - savedCost
                    if costDelta < bestCostDelta {
                        bestCostDelta = costDelta
                        bestAssignIdx = i
                    }
                }
                dispatch.Assigns[i].RemoveShip(shipId)
                dispatch.Assigns[i].GenRoute()
                dispatch.Assigns[i].Cost = savedCost
            }
        }
        // Commit to best existing assign if found
        if bestAssignIdx != -1 {
            dispatch.Assigns[bestAssignIdx].AddShip(shipId, oris[orderIdx], dess[orderIdx])
            dispatch.Assigns[bestAssignIdx].GenRoute()
            continue
        }
        // Fallback: try empty/new assigns up to MAXASSIGNS
        fallbackAssigned := false
        for i := 0; i < MAXASSIGNS; i++ {
            if i >= dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
            // Only use empty assigns (no stations yet) for simplicity
            // We rely on AddShip's internal feasibility check
            if dispatch.Assigns[i].AddShip(shipId, oris[orderIdx], dess[orderIdx]) {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    fallbackAssigned = true
                    break
                } else {
                    dispatch.Assigns[i].RemoveShip(shipId)
                    dispatch.Assigns[i].GenRoute()
                }
            }
        }
        if !fallbackAssigned {
            // Force create new assign at next slot (should always work per problem guarantee)
            if dispatch.AssignsLen >= MAXASSIGNS {
                dispatch.AssignsLen = MAXASSIGNS - 1
            }
            idx := dispatch.AssignsLen
            dispatch.Assigns[idx].AddShip(shipId, oris[orderIdx], dess[orderIdx])
            dispatch.Assigns[idx].GenRoute()
            dispatch.AssignsLen++
        }
    }
