Greedy insertion with time window feasibility priority and capacity-aware slot scoring, using delta cost ratio weighted by load efficiency and distance savings, with fallback to earliest available empty assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type savedState struct {
		Cost           float64
		StationsLen    int
		StationCurrent Station
	}
	savedStates := make([]savedState, MAXASSIGNS)
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestAssignIdx := -1
		bestScore := -1e308
		fallbackAssignIdx := -1
		baseLoad := oris[orderIdx].Load
		if baseLoad <= 0 {
			baseLoad = 1
		}
		for assignIdx := 0; assignIdx < MAXASSIGNS; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]
			if assignIdx >= dispatch.AssignsLen && assignIdx > 0 && dispatch.Assigns[assignIdx-1].StationsLen == 0 {
				continue
			}
			if assign.StationsLen == 0 && assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = assignIdx + 1
			}
			savedStates[assignIdx] = savedState{
				Cost:           assign.Cost,
				StationsLen:    assign.StationsLen,
				StationCurrent: assign.StationCurrent,
			}
			success := assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if success {
				oldCost := assign.Cost
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				var distSaving float64 = 0
				if assign.StationsLen > 2 {
					lastIdx := assign.StationsLen - 1
					prevLast := assign.Stations[lastIdx-1]
					lastSta := assign.Stations[lastIdx]
					distSaving = cal_dis(prevLast, lastSta)
				}
				scoreNumerator := (distSaving + 1.0) / (delta + 1.0)
				loadFactor := float64(baseLoad) / float64(assign.StationsLen+1)
				timeFeasible := 1.0
				if oris[orderIdx].TimeStart > 0 && oris[orderIdx].TimeEnd > oris[orderIdx].TimeStart {
					timeWindowRange := float64(oris[orderIdx].TimeEnd - oris[orderIdx].TimeStart + 1)
					timeFeasible = 10000.0 / (timeWindowRange + 1.0)
				}
				compositeScore := scoreNumerator*loadFactor*timeFeasible - delta*0.01
				if compositeScore > bestScore {
					bestScore = compositeScore
					bestAssignIdx = assignIdx
				}
				assign.RemoveShip(total_ship + orderIdx)
				assign.GenRoute()
				assign.Cost = savedStates[assignIdx].Cost
				assign.StationsLen = savedStates[assignIdx].StationsLen
				assign.StationCurrent = savedStates[assignIdx].StationCurrent
			} else {
				if assignIdx >= dispatch.AssignsLen && fallbackAssignIdx == -1 {
					fallbackAssignIdx = assignIdx
				}
			}
		}
		targetIdx := bestAssignIdx
		if targetIdx == -1 {
			if fallbackAssignIdx == -1 {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].StationsLen == 0 && i >= dispatch.AssignsLen {
						fallbackAssignIdx = i
						break
					}
				}
				if fallbackAssignIdx == -1 {
					fallbackAssignIdx = dispatch.AssignsLen
					if fallbackAssignIdx >= MAXASSIGNS {
						fallbackAssignIdx = MAXASSIGNS - 1
					}
				}
			}
			targetIdx = fallbackAssignIdx
		}
		assign := &dispatch.Assigns[targetIdx]
		if targetIdx >= dispatch.AssignsLen {
			dispatch.AssignsLen = targetIdx + 1
		}
		ok := assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
		if ok {
			assign.GenRoute()
		} else {
			if assign.StationsLen == 0 {
				ok = assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				if ok {
					assign.GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

