Greedy randomized adaptive search with cost‑delta trials and fallback creation.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e308
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		// Try all existing assigns (including empty slots up to AssignsLen)
		for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
			assign := &dispatch.Assigns[assignIdx]
			oldCost := assign.Cost
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				costDelta := newCost - oldCost
				if costDelta < 0 || oldCost < 0 { // first successful insert into empty assign yields negative oldCost; treat as candidate
					// rollback trial
					assign.RemoveShip(shipID)
					assign.GenRoute()
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = assignIdx
					}
				} else {
					// positive or zero delta, also consider if better than current best
					assign.RemoveShip(shipID)
					assign.GenRoute()
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = assignIdx
					}
				}
			}
		}

		// Also try a potential new assign slot if within MAXASSIGNS
		if bestAssignIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[fallbackIdx]
			ok := assign.AddShip(shipID, ori, des)
			if ok {
				assign.GenRoute()
				assign.RemoveShip(shipID)
				assign.GenRoute()
				bestAssignIdx = fallbackIdx
				bestCostDelta = assign.Cost // will be overwritten later
			}
		}

		// Commit the best insertion found
		if bestAssignIdx != -1 {
			assign := &dispatch.Assigns[bestAssignIdx]
			success := assign.AddShip(shipID, ori, des)
			if success {
				assign.GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = bestAssignIdx + 1
				}
			} else {
				// Should not happen because we already tested; fallback to force-create at next free slot
				found := false
				for i := 0; i < MAXASSIGNS; i++ {
					idx := (dispatch.AssignsLen + i) % MAXASSIGNS
					a := &dispatch.Assigns[idx]
					if a.AddShip(shipID, ori, des) {
						a.GenRoute()
						if idx >= dispatch.AssignsLen {
							dispatch.AssignsLen = idx + 1
						}
						found = true
						break
					}
				}
				if !found {
					// Last resort: expand AssignsLen if possible and use that slot
					if dispatch.AssignsLen < MAXASSIGNS {
						a := &dispatch.Assigns[dispatch.AssignsLen]
