type savedState struct {
	cost        float64
	stationCurr Station
	routeHash   uint64
}
saveAssign := func(a *Assign) savedState {
	return savedState{cost: a.Cost, stationCurr: a.StationCurrent}
}
restoreAssign := func(a *Assign, s savedState) {
	a.Cost = s.cost
	a.StationCurrent = s.stationCurr
}
for idx := 0; idx < orderCount; idx++ {
	insertID := total_ship + idx
	ori := oris[idx]
	des := dess[idx]
	type candidate struct {
		assignIdx int
		score     float64
		valid     bool
	}
	var bestCandidate candidate
	bestCandidate.score = 1e300
	bestCandidate.valid = false
	baseDist := cal_dis(ori, des)
	loadSum := ori.Load + des.Load
	urgency := 0.0
	if ori.TimeEnd > ori.TimeStart {
		urgency = 1.0 / float64(ori.TimeEnd-ori.TimeStart+1)
	}
	priorityWeight := 1.0 + float64(loadSum)*0.005 + urgency*0.5
	for ai := 0; ai < dispatch.AssignsLen; ai++ {
		assignPtr := &dispatch.Assigns[ai]
		stateBefore := saveAssign(assignPtr)
		okAdd := assignPtr.AddShip(insertID, ori, des)
		if !okAdd {
			continue
		}
		assignPtr.GenRoute()
		if assignPtr.Cost < 0 || assignPtr.Cost < stateBefore.cost-1e9 {
			assignPtr.RemoveShip(insertID)
			assignPtr.GenRoute()
			restoreAssign(assignPtr, stateBefore)
			continue
		}
		deltaCost := assignPtr.Cost - stateBefore.cost
		if deltaCost < 0 {
			deltaCost = 0
		}
		utilizationBonus := 1.0
		if assignPtr.StationCurrent.ReqCode != 0 {
			utilizationBonus = 1.0 - float64(ai%7)*0.001
		}
		scoreVal := deltaCost*priorityWeight*utilizationBonus + baseDist*0.0001
		if scoreVal < bestCandidate.score {
			bestCandidate = candidate{assignIdx: ai, score: scoreVal, valid: true}
		}
		assignPtr.RemoveShip(insertID)
		assignPtr.GenRoute()
		restoreAssign(assignPtr, stateBefore)
	}
	inserted := false
	if bestCandidate.valid {
		targetAssign := &dispatch.Assigns[bestCandidate.assignIdx]
		stateBeforeFinal := saveAssign(targetAssign)
		okFinal := targetAssign.AddShip(insertID, ori, des)
		if okFinal {
			targetAssign.GenRoute()
			if targetAssign.Cost >= 0 && !(targetAssign.Cost < stateBeforeFinal.cost-1e9) {
				inserted = true
			} else {
				targetAssign.RemoveShip(insertID)
				targetAssign.GenRoute()
				restoreAssign(targetAssign, stateBeforeFinal)
			}
