			if !addOk {
				continue
			}
			as.GenRoute()
			newCost := as.Cost
			if newCost < 0 {
				as.RemoveShip(insertId)
				as.GenRoute()
				continue
			}
			delta := newCost - oldCost
			currentLoad := 0.0
			if as.StationCurrent.ReqCode != 0 {
				currentLoad += float64(as.StationCurrent.Load)
			}
			loadBalanceFactor := 1.0
			if currentLoad > 0 {
				loadBalanceFactor = 1.0 + (currentLoad/float64(MAXASSIGNS))*0.001
			}
			score := delta*(1.0+prioScore*0.0001)*loadBalanceFactor
			candidates = append(candidates, cand{assignIdx: ai, score: score, isNew: false})
			as.RemoveShip(insertId)
			as.GenRoute()
		}
		sort.Slice(candidates, func(i, j int) bool { return candidates[i].score < candidates[j].score })
		if len(candidates) > 3 {
			candidates = candidates[:3]
		}
		bestCand := cand{assignIdx: -1, score: 1e100, isNew: false}
		found := false
		for _, c := range candidates {
			as := &dispatch.Assigns[c.assignIdx]
			if as.AddShip(insertId, ori, des) {
				as.GenRoute()
				if as.Cost >= 0 {
					bestCand = c
					found = true
					break
				}
				as.RemoveShip(insertId)
				as.GenRoute()
			}
		}
		if !found {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				as := &dispatch.Assigns[newIdx]
				if as.AddShip(insertId, ori, des) {
					as.GenRoute()
					dispatch.AssignsLen++
					found = true
				}
			}
			if !found {
				safeSeedIdx := -1
				for si := 0; si < MAXASSIGNS; si++ {
					as := &dispatch.Assigns[si]
					if as.StationsLen == 0 {
						safeSeedIdx = si
						break
					}
				}
				if safeSeedIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
					safeSeedIdx = dispatch.AssignsLen
				}
				if safeSeedIdx >= 0 && safeSeedIdx < MAXASSIGNS {
					as := &dispatch.Assigns[safeSeedIdx]
					if as.AddShip(insertId, ori, des) {
						as.GenRoute()
						if safeSeedIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = safeSeedIdx + 1
						}
					}
				}
			}
		} else {
			as := &dispatch.Assigns[bestCand.assignIdx]
			if !as.AddShip(insertId, ori, des) {
				if as.AddShip(insertId, ori, des) {
					as.GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

