func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	shipCount := len(oris)
	for sIdx := 0; sIdx < shipCount; sIdx++ {
		bestAssignIdx := -1
		var bestSavedState Assign
		minScore := 1e18
		shipID := total_ship + sIdx
		ori := oris[sIdx]
		des := dess[sIdx]
		maxTries := dispatch.AssignsLen + 1
		if maxTries > MAXASSIGNS {
			maxTries = MAXASSIGNS
		}
		type candidate struct {
			idx  int
			cost float64
		}
		var candidates []candidate
		for aIdx := 0; aIdx < maxTries; aIdx++ {
			saved := dispatch.Assigns[aIdx]
			success := dispatch.Assigns[aIdx].AddShip(shipID, ori, des)
			if !success {
				dispatch.Assigns[aIdx] = saved
				continue
			}
			oldCost := dispatch.Assigns[aIdx].Cost
			dispatch.Assigns[aIdx].GenRoute()
			newCost := dispatch.Assigns[aIdx].Cost
			if newCost < 0 || oldCost < 0 {
				dispatch.Assigns[aIdx].RemoveShip(shipID)
				dispatch.Assigns[aIdx].GenRoute()
				dispatch.Assigns[aIdx] = saved
				continue
			}
			delta := newCost - oldCost
			candidates = append(candidates, candidate{aIdx, delta})
			currentAssign := dispatch.Assigns[aIdx]
			dispatch.Assigns[aIdx].RemoveShip(shipID)
			dispatch.Assigns[aIdx].GenRoute()
			dispatch.Assigns[aIdx] = saved
			proximityPenalty := 0.0
			if currentAssign.StationCurrent.X != 0 || currentAssign.StationCurrent.Y != 0 {
				depotDist := cal_dis(currentAssign.StationCurrent, ori)
				proximityPenalty = depotDist * 0.3
			}
			score := delta + proximityPenalty
			if len(candidates) > 1 {
				regret := 0.0
				for _, c := range candidates {
					if c.idx != aIdx && c.cost-delta > regret {
						regret = c.cost - delta
					}
				}
				score += regret * 0.5
			}
			if score < minScore {
				minScore = score
				bestAssignIdx = aIdx
				bestSavedState = saved
			}
		}
		if bestAssignIdx >= 0 {
			temp := dispatch.Assigns[bestAssignIdx]
			dispatch.Assigns[bestAssignIdx] = bestSavedState
			success := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if dispatch.Assigns[bestAssignIdx].Cost < 0 {
					dispatch.Assigns[bestAssignIdx] = temp
				}
			} else {
				dispatch.Assigns[bestAssignIdx] = temp
			}
		}
		fallbackDone := false
		if bestAssignIdx < 0 || dispatch.Assigns[bestAssignIdx].Cost < 0 {
			targetIdx := dispatch.AssignsLen
			if targetIdx >= MAXASSIGNS {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].StationsLen == 0 {
						targetIdx = i
						break
					}
				}
			}
			if targetIdx < MAXASSIGNS {
				saved := dispatch.Assigns[targetIdx]
				success := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[targetIdx].GenRoute()
					if dispatch.Assigns[targetIdx].Cost >= 0 {
						if targetIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						fallbackDone = true
					} else {
						dispatch.Assigns[targetIdx] = saved
					}
				}
			}
		}
		if !fallbackDone && bestAssignIdx < 0 {
			for i := 0; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					saved := dispatch.Assigns[i]
					success := dispatch.Assigns[i].AddShip(shipID, ori, des)
					if success {
						dispatch.Assigns[i].GenRoute()
						if dispatch.Assigns[i].Cost >= 0 {
							if i >= dispatch.AssignsLen {
								dispatch.AssignsLen++
							}
							break
						} else {
							dispatch.Assigns[i] = saved
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
